icon = open('/opt/quirrely/quirrely_v313_integrated/assets/logo/logo-icon.svg').read().strip()
wm = open('/opt/quirrely/quirrely_v313_integrated/assets/logo/wordmark.svg').read().strip()
css = ":root{--bg:#FFFBF5;--coral:#FF6B6B;--ink:#2D3436;--muted:#636E72;--dim:#A0AEC0;--border:#E9ECEF;}*{margin:0;padding:0;box-sizing:border-box;}body{font-family:'Nunito Sans',sans-serif;background:var(--bg);color:var(--ink);min-height:100vh;display:flex;align-items:center;justify-content:center;}.container{max-width:560px;width:100%;padding:60px 32px;text-align:center;}.a1{animation:fu .7s ease .1s both;}.a2{animation:fu .7s ease .25s both;}.a3{animation:fu .7s ease .38s both;}.a4{animation:fu .7s ease .51s both;}.a5{animation:fu .7s ease .64s both;}.a6{animation:fu .7s ease .77s both;}@keyframes fu{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}.logo-wrap{display:flex;align-items:center;justify-content:center;gap:16px;margin-bottom:10px;}.logo-wrap svg:first-child{width:56px;height:67px;}.tagline{font-style:italic;font-size:1.05rem;color:var(--muted);margin-bottom:28px;}.divider{display:flex;align-items:center;gap:10px;margin:0 auto 24px;max-width:280px;}.divider:before,.divider:after{content:'';flex:1;height:1px;background:var(--border);}.dot{width:4px;height:4px;border-radius:50%;background:var(--coral);opacity:.5;margin:0 2px;display:inline-block;}.body-text{font-size:.975rem;line-height:1.8;color:var(--muted);margin-bottom:36px;}.countdown{display:flex;justify-content:center;gap:10px;margin-bottom:40px;}.cu{display:flex;flex-direction:column;align-items:center;gap:6px;}.cn{font-family:'Outfit',sans-serif;font-size:2rem;font-weight:700;background:#fff;border:1px solid var(--border);border-radius:10px;min-width:62px;padding:12px 8px 10px;line-height:1;text-align:center;}.cl{font-size:.62rem;letter-spacing:.12em;text-transform:uppercase;color:var(--dim);font-weight:600;}.form-label{font-size:.72rem;letter-spacing:.14em;text-transform:uppercase;color:var(--dim);font-weight:600;margin-bottom:10px;display:block;}.form-row{display:flex;max-width:400px;margin:0 auto;border-radius:10px;overflow:hidden;border:1.5px solid var(--border);background:#fff;}.form-row input{flex:1;padding:13px 16px;background:transparent;border:none;color:var(--ink);font-size:.9rem;outline:none;min-width:0;}.form-row input::placeholder{color:var(--dim);}.form-row button{padding:13px 20px;background:var(--coral);color:white;border:none;font-family:'Outfit',sans-serif;font-size:.8rem;font-weight:600;cursor:pointer;white-space:nowrap;}.form-row button:disabled{opacity:.6;}.success{font-style:italic;color:var(--coral);font-size:.875rem;margin-top:10px;display:none;}.social{margin-top:28px;}.social a{display:inline-flex;align-items:center;gap:7px;color:var(--muted);text-decoration:none;font-size:.8rem;font-weight:500;padding:8px 16px;border-radius:8px;border:1px solid var(--border);background:#fff;}.social a:hover{color:var(--coral);}.social svg{width:14px;height:14px;fill:currentColor;}.footer{margin-top:24px;font-size:.72rem;color:var(--dim);}"
js = 'var launch=new Date("2026-02-25T05:01:00Z");function pad(n){return String(n).padStart(2,"0");}function tick(){var d=launch-new Date();if(d<=0){document.getElementById("cd").innerHTML="<p style=\'font-family:Outfit,sans-serif;font-size:1.3rem;font-weight:700;color:#FF6B6B\'>We are live.</p>";return;}document.getElementById("days").textContent=pad(Math.floor(d/86400000));document.getElementById("hours").textContent=pad(Math.floor((d%86400000)/3600000));document.getElementById("mins").textContent=pad(Math.floor((d%3600000)/60000));document.getElementById("secs").textContent=pad(Math.floor((d%60000)/1000));}tick();setInterval(tick,1000);function signup(){var e=document.getElementById("em").value;if(!e||e.indexOf("@")<0)return;var btn=document.getElementById("btn");btn.textContent="Sending...";btn.disabled=true;fetch("https://api.quirrely.com/notify",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email:e})}).then(function(r){return r.json();}).then(function(){document.getElementById("msg").style.display="block";document.getElementById("em").value="";btn.textContent="Notify Me";btn.disabled=false;}).catch(function(){btn.textContent="Try Again";btn.disabled=false;});}'
h = '<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Quirrely - Coming Soon</title><link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700;800&family=Nunito+Sans:ital,wght@0,300;0,400;0,500;1,400&display=swap" rel="stylesheet"><style>'+css+'</style></head><body><div class="container"><div class="logo-wrap a1">'+icon+wm+'</div><p class="tagline a2">The mirror for your writing.</p><div class="divider a2"><span class="dot"></span><span class="dot"></span><span class="dot"></span></div><p class="body-text a3">For authors, content creators, students, and professionals<br>that want to sound like themselves - not AI.</p><div class="countdown a4" id="cd"><div class="cu"><div class="cn" id="days">00</div><div class="cl">Days</div></div><div class="cu"><div class="cn" id="hours">00</div><div class="cl">Hours</div></div><div class="cu"><div class="cn" id="mins">00</div><div class="cl">Minutes</div></div><div class="cu"><div class="cn" id="secs">00</div><div class="cl">Seconds</div></div></div><div class="a5"><label class="form-label">Be first to know</label><div class="form-row"><input type="email" id="em" placeholder="your@email.com"><button id="btn" onclick="signup()">Notify Me</button></div><p class="success" id="msg">You are on the list. We will be in touch.</p></div><div class="social a6"><a href="https://www.linkedin.com/company/quirrely" target="_blank" rel="noopener"><svg viewBox="0 0 24 24"><path d="M20.447 20.452h-3.554v-5.569c0-1.328-.027-3.037-1.852-3.037-1.853 0-2.136 1.445-2.136 2.939v5.667H9.351V9h3.414v1.561h.046c.477-.9 1.637-1.85 3.37-1.85 3.601 0 4.267 2.37 4.267 5.455v6.286zM5.337 7.433a2.062 2.062 0 01-2.063-2.065 2.064 2.064 0 112.063 2.065zm1.782 13.019H3.555V9h3.564v11.452zM22.225 0H1.771C.792 0 0 .774 0 1.729v20.542C0 23.227.792 24 1.771 24h20.451C23.2 24 24 23.227 24 22.271V1.729C24 .774 23.2 0 22.222 0h.003z"/></svg>Follow on LinkedIn</a></div><p class="footer a7">quirrely.ca &#127464;&#127462;</p></div><script>'+js+'</script></body></html>'
open('/home/quirrely/public_html/index.html','w').write(h)
